  centers[4] = vec3(-0.8,  0.0,  1.0); radii[4] = 0.38; albedo[4] = vec3(0.8, 0.5,  0.2); rough[4] = 0.65;
  centers[5] = vec3( 0.0,  0.6, -0.8); radii[5] = 0.30; albedo[5] = vec3(0.85,0.85, 0.9); rough[5] = 0.0;
